import { fromNodeProviderChain } from '@aws-sdk/credential-providers';
import { NextResponse } from 'next/server';

/**
 * Server-side route that resolves AWS credentials from the default provider chain:
 *   1. Environment variables (AWS_ACCESS_KEY_ID, etc.)
 *   2. ~/.aws/credentials  (shared credentials file)
 *   3. ~/.aws/config       (SSO, assume-role)
 *   4. ECS / EC2 instance metadata
 *
 * Returns { accessKeyId, secretAccessKey, sessionToken? } to the client.
 */
export async function GET() {
  try {
    const provider = fromNodeProviderChain();
    const creds = await provider();
    return NextResponse.json({
      accessKeyId: creds.accessKeyId,
      secretAccessKey: creds.secretAccessKey,
      sessionToken: creds.sessionToken,
    });
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    return NextResponse.json(
      { error: `Failed to resolve AWS credentials: ${message}` },
      { status: 500 }
    );
  }
}
